body:
### Version

0.27-22

### On which OS did this happen?

Linux

### Reproduction Steps

### TEST

    module test_dffsr(clk, data, out, rst, set);
        input clk, data, rst, set;
        output reg out;
        always @(negedge clk, negedge rst, negedge set )
            if (rst == 0)
                out <= 1'b0;
            else if (set == 0)
                out <= 1'b1;
            else 
                out <= data;
    endmodule

### SCRIPT
    read_verilog test_dffsr.v
    hierarchy -check -top test_dffsr
    proc; opt;
    dfflegalize -cell $_DFFSR_NNN_ x;
    techmap; opt;
    write_verilog -noattr -noexpr test_dffsr.syn.v


### Expected Behavior

    module test_dffsr(clk, data, out, rst, set);
      input clk;
      wire clk;
      input data;
      wire data;
      output out;
      wire out;
      input rst;
      wire rst;
      input set;
      wire set;
      \$_DFFSR_NNN_  out_reg (
        .C(clk),
        .D(data),
        .Q(out),
        .R(rst),
        .S(set)
      );
    endmodule

### Actual Behavior

      module test_dffsr(clk, data, out, rst, set);
        wire _0_;
        wire _1_;
        input clk;
        wire clk;
        input data;
        wire data;
        output out;
        wire out;
        input rst;
        wire rst;
        input set;
        wire set;
        \$_DFFSR_NPN_  out_reg /* _2_ */ (
          .C(clk),
          .D(data),
          .Q(out),
          .R(rst),
          .S(_0_)
        );
        \$_NOT_  _3_ (
          .A(set),
          .Y(_1_)
        );
        \$_MUX_  _4_ (
          .A(1'h0),
          .B(_1_),
          .S(rst),
          .Y(_0_)
        );
      endmodule
